     1→/**
     2→ * 用 Playwright (Chromium) 将 HTML 打印为 PDF。
     3→ * 用法: node print-to-pdf.js <input.html> <output.pdf>
     4→ */
     5→const { chromium } = require('playwright');
     6→const path = require('path');
     7→const fs = require('fs');
     8→
     9→const HEADER = '上手 Skill —— Agent Skill 设计、实战与评估全指南 | github.com/liuchunming033/hands-on-Skill';
    10→
    11→(async () => {
    12→  const input = path.resolve(process.argv[2]);
    13→  const output = path.resolve(process.argv[3]);
    14→
    15→  if (!fs.existsSync(input)) {
    16→    console.error(`❌ 文件不存在: ${input}`);
    17→    process.exit(1);
    18→  }
    19→
    20→  const browser = await chromium.launch();
    21→  const page = await browser.newPage();
    22→  await page.goto('file://' + input, { waitUntil: 'networkidle' });
    23→  await page.pdf({
    24→    path: output,
    25→    format: 'A4',
    26→    margin: { top: '1.5cm', right: '2.5cm', bottom: '2.5cm', left: '2.5cm' },
    27→    printBackground: true,
    28→    displayHeaderFooter: true,
    29→    headerTemplate: `<div style="font-size:9px;text-align:center;width:100%;color:#888;font-family:'Noto Sans SC','PingFang SC','Microsoft YaHei',sans-serif;padding:5px 0 3px;border-bottom:1px solid #d0d7de;">${HEADER}</div>`,
    30→    footerTemplate: '<div></div>'
    31→  });
    32→  await browser.close();
    33→  console.log(`  ✓ ${path.basename(output)}`);
    34→})();
